import{_ as t,o as e,c as h,a2 as p}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"伯克希尔哈撒韦·伯克希尔哈撒韦公司","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2023年/翻译.md","filePath":"01_letters/2023年/翻译.md"}'),o={name:"01_letters/2023年/翻译.md"};function m(r,a,l,i,n,s){return e(),h("div",null,[...a[0]||(a[0]=[p('<h1 id="伯克希尔哈撒韦·伯克希尔哈撒韦公司" tabindex="-1"><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>·<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>公司 <a class="header-anchor" href="#伯克希尔哈撒韦·伯克希尔哈撒韦公司" aria-label="Permalink to &quot;[[伯克希尔哈撒韦]]·[[伯克希尔哈撒韦]]公司&quot;">​</a></h1><h1 id="致伯克希尔哈撒韦·伯克希尔哈撒韦公司全体股东" tabindex="-1">致<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>·<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>公司全体股东： <a class="header-anchor" href="#致伯克希尔哈撒韦·伯克希尔哈撒韦公司全体股东" aria-label="Permalink to &quot;致[[伯克希尔哈撒韦]]·[[伯克希尔哈撒韦]]公司全体股东：&quot;">​</a></h1><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的股东账户超过300万个。我每年都肩负着一项使命：撰写一封对这群多元且不断变化的投资者群体有用的信，许多人希望借此更深入地了解他们的投资。</p><p>我的搭档查理·<a href="/04_people/查理·芒格.html">查理·芒格</a>在管理<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>数十年来，一直以同样的态度看待这一使命，也会期望我今年以常规方式与各位交流。他与我在对<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>股东的责任方面始终保持一致。</p><hr><h2 id="查理·查理·芒格——伯克希尔哈撒韦·伯克希尔哈撒韦的缔造者" tabindex="-1">查理·<a href="/04_people/查理·芒格.html">查理·芒格</a>——<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>·<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的缔造者 <a class="header-anchor" href="#查理·查理·芒格——伯克希尔哈撒韦·伯克希尔哈撒韦的缔造者" aria-label="Permalink to &quot;查理·[[查理·芒格]]——[[伯克希尔哈撒韦]]·[[伯克希尔哈撒韦]]的缔造者&quot;">​</a></h2><p>查理·<a href="/04_people/查理·芒格.html">查理·芒格</a>于11月28日去世，距离他的100岁生日仅剩33天。</p><p>虽然查理发迹并成长于奥马哈，但他80%的人生在其他地方度过。因此，直到1959年他35岁时，我才第一次见到他。</p><p>1962年，他决定投身资金管理行业。三年后，他准确地告诉我，我在收购<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的控制权时做了一个愚蠢的决定。但他向我保证，既然我已经迈出了这一步，他会告诉我如何纠正这个错误。</p><p>在我接下来要讲述的故事中，请记住：查理和他的家人当时并没有在我管理的小型投资合伙企业中投入一分钱，而我正是用那笔资金购买了<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>。此外，我们两人都没有预料到查理有朝一日会持有<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的股票。</p><p>尽管如此，查理在1965年立即建议我：&quot;沃伦，别再想着收购像<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>这样的公司了。但既然你已经控制了<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，就用合理的价格收购优秀企业并不断添加到公司中，而不要再用离谱的价格去买普通的企业。换句话说，放弃你从英雄本杰明·<a href="/04_people/本·格雷厄姆.html">本·格雷厄姆</a>那里学到的一切。它有效，但只在小型规模上实践时才有效。&quot;经过多次反复，我最终听从了他的指导。</p><p>多年以后，查理成为了我经营<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的合伙人，他一次又一次地将我从旧习惯中拉回理智。直到他去世之前，他一直扮演着这个角色。最终，我们以及早期信任我们的投资者，都获得了远超查理和我曾经梦想过的财富。</p><p>事实上，查理是今日<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的&quot;缔造者&quot;，而我则担任&quot;总承包商&quot;，负责日复一日地实现他的愿景。</p><p>查理从不寻求将创造者的角色归功于自己，而是让我接受掌声和赞誉。从某种意义上说，他与我的关系既是兄长，又是慈父。即使他知道自己的是正确的，他也会把缰绳交给我；而当我犯错误时，他也从不会——一次都不会——提醒我。</p><p>在现实世界中，伟大的建筑与其建筑师紧密相连，而那些浇筑混凝土或安装窗户的人很快就会被遗忘。<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>已经成为一家伟大的企业。虽然我长期以来一直负责施工团队的工作，但查理永远应该是那位缔造者。</p><hr><h2 id="致股东信" tabindex="-1">致股东信 <a class="header-anchor" href="#致股东信" aria-label="Permalink to &quot;致股东信&quot;">​</a></h2><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>拥有超过300万个股东账户。我每年都肩负着一项使命：撰写一封对这群多元且不断变化的投资者群体有用的信，许多人希望借此更深入地了解他们的投资。</p><p>查理·<a href="/04_people/查理·芒格.html">查理·芒格</a>数十年来一直是我的搭档，他对这一使命的看法与我完全一致，也会期望我今年以常规方式与各位交流。他与我在对<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>股东的责任方面始终保持一致。</p><hr><p>作家们发现，为想象中的读者勾勒画像是有用的，他们常常希望吸引大量读者。而在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，我们的目标更为有限：吸引那些将积蓄托付给<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>、并不打算转售的投资者（他们的心态类似于那些为了购买农场或出租物业而储蓄的人，而不是那些喜欢用多余资金购买彩票或&quot;热门&quot;股票的人）。</p><p>多年来，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>吸引了大量这样的&quot;终身&quot;股东及其继承人。我们珍视他们的存在，并相信他们有权每年直接听到来自CEO的好消息和坏消息，而不是从投资者关系官或公关顾问那里永远听到乐观和甜腻的废话。</p><p>在想象<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的目标股东时，我很幸运地拥有完美的参照模型——我的姐姐伯蒂。让我来介绍一下她。</p><p>首先，伯蒂聪明、有智慧，喜欢挑战我的想法。然而，我们从未有过争吵或任何接近破裂的关系。我们永远不会有。</p><p>此外，伯蒂以及她的三个女儿都将大量储蓄投入了<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的股票。她们的持股跨越了几十年，每年伯蒂都会阅读我写的内容。我的工作是预判她的问题，并给出诚实的答案。</p><p>伯蒂和大多数人一样，理解许多会计术语，但她还没有准备好参加注册会计师考试。她关注商业新闻——每天阅读四份报纸——但不认为自己是经济专家。她很明智——非常明智——本能地知道权威人士应该始终被忽视。毕竟，如果她能够可靠地预测明天的赢家，她会免费分享她宝贵的见解，从而增加竞争性购买吗？这就像找到黄金后把藏宝图交给邻居一样。</p><p>伯蒂理解激励的力量——无论是好的还是坏的——人类的不完美，以及在观察人类行为时可以识别的&quot;小动作&quot;。她知道谁是&quot;卖家&quot;，谁值得信任。简而言之，她不是任何人的傻瓜。</p><p>那么，今年伯蒂会关心什么呢？</p><hr><h2 id="经营业绩-事实与虚构" tabindex="-1">经营业绩：事实与虚构 <a class="header-anchor" href="#经营业绩-事实与虚构" aria-label="Permalink to &quot;经营业绩：事实与虚构&quot;">​</a></h2><p>让我们从数字开始。官方年度报告从K-1页开始，共124页。里面充斥着大量信息——有些重要，有些则不然。</p><p>在其披露内容中，许多股东和财经记者会关注第K-72页。在那里，他们会看到传说中的&quot;最终底线&quot;，标注为&quot;净收益（亏损）&quot;。数字显示：2021年为900亿美元，2022年为（230亿美元），2023年为960亿美元。</p><p>这到底是怎么回事？</p><p>你寻求指导，被告知这些&quot;收益&quot;的计算方法是由严谨且资质深厚的财务会计准则委员会（&quot;FASB&quot;）制定的，由勤奋的证券交易委员会（&quot;SEC&quot;）强制执行，并由德勤的顶级专业人士进行审计。在第K-67页，德勤毫不含糊地声明：&quot;我们认为，财务报表......在所有重大方面（我的强调），公正地呈现了公司的财务状况......及其经营成果......截至2023年12月31日的三年期内的每一年度......&quot;</p><p>带着这样的背书，这个比无用更糟的&quot;净收益&quot;数字迅速通过互联网和媒体传播到全世界。各方都认为自己完成了职责——从法律上讲，他们确实完成了。</p><p>然而，我们感到不安。在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，我们认为&quot;收益&quot;应该是一个理性的概念，伯蒂会发现它略有用途——但只是作为评估企业的起点。因此，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>也向伯蒂和各位报告我们所说的&quot;经营收益&quot;。它们显示的数字是：2021年276亿美元；2022年309亿美元；2023年374亿美元。</p><p>会计准则规定的数字与我们偏好的数字之间的主要区别在于，我们排除了未实现的资本利得或损失，这些有时每天可能超过50亿美元。具有讽刺意味的是，我们的偏好直到2018年才基本上成为规则，当时&quot;改进&quot;被强制执行。几个世纪前伽利略的经历应该教会我们不要干涉来自高层的强制命令。但在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，我们可以固执。</p><p>不要误解资本利得的重要性：我预计它们将成为<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>未来数十年价值增值的重要组成部分。否则，我们为什么要像我在整个投资生涯中用我自己的资金一样，将大量资金投入股票呢？</p><p>自1942年3月11日——我第一次购买股票的那一天——以来，我不记得有哪个时期我的净资产中没有以美国股票为主的形式占多数。到目前为止，一切顺利。在我&quot;扣动扳机&quot;的那天，道琼斯工业平均指数跌破100点。当天放学时，我亏损了大约5美元。很快，情况就逆转了，如今该指数在38000点左右徘徊。美国一直是投资者的乐土。他们需要做的只是安静地坐着，不听任何人的话。</p><p>然而，根据incorporate股票市场每日——是的，甚至是年度——波动无常的&quot;收益&quot;来评判<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的投资价值，是非常愚蠢的。正如本杰明·<a href="/04_people/本·格雷厄姆.html">本·格雷厄姆</a>教我的：&quot;短期内，市场是一台投票机；长期来看，它变成了一台称重机。&quot;</p><hr><h2 id="我们做什么" tabindex="-1">我们做什么 <a class="header-anchor" href="#我们做什么" aria-label="Permalink to &quot;我们做什么&quot;">​</a></h2><p>我们在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的目标很简单：我们希望拥有具有基本且持久良好经济效益的企业——全部或部分拥有。在资本主义体系中，一些企业将长期繁荣，而另一些将被证明是资金黑洞。预测谁是赢家谁是输家比你想象的要难。那些告诉你他们知道答案的人通常要么是自欺欺人，要么是江湖骗子。</p><p>在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，我们特别青睐那些罕见的企业——它们能够在未来以高回报率部署额外资本。仅仅拥有一家这样的公司——然后坐稳——就可以带来几乎难以衡量的财富。这些公司的继承人甚至可以——呃！——一辈子悠闲地生活。</p><p>我们也希望这些受青睐的企业由有能力且值得信赖的管理者经营，虽然这是一个更难做出的判断，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>也有过令人失望的时候。</p><p>1863年，美国第一任审计长休·麦克洛给所有国民银行写了一封信。他的指示包括以下警告：&quot;永远不要指望在与骗子打交道时能阻止他欺骗你。&quot;许多认为自己能够&quot;管理&quot;骗子问题的银行家已经学会了麦克洛先生建议的智慧——我也是。人们并不那么容易读懂。真诚和同理心很容易被伪装。这一点在1863年和现在一样真实。</p><p>这种结合我所描述的收购企业的两个必要条件的组合长期以来一直是我们在收购中的目标，有一段时间我们有大量的候选对象可供评估。如果我错过了一个——我错过了很多——另一个总是会出现。</p><p>那些日子早已远去；规模是我们的障碍，尽管收购竞争加剧也是一个因素。</p><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>目前拥有——远远超过——任何美国企业有记录以来最大的GAAP净资产。创纪录的经营收入和强劲的股票市场使年底数字达到5610亿美元。其他499家标准普尔500公司——美国商业的名人录——2022年的GAAP净资产总额为8.9万亿美元。（2023年标准普尔500公司的数据尚未汇总，但不太可能大幅超过9.5万亿美元。）</p><p>按这个标准，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>现在占据了我们所处领域的近6%。在比如说五年内将我们庞大的基数翻一番根本不可能，特别是因为我们非常不愿意发行股票（这种行为会立即增加净资产）。</p><p>这个国家只有少数公司能够真正对<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>产生影响，而且它们已经被我们和其他人反复筛选。有些我们能估值，有些不能。而且，即使我们能估值，价格也必须具有吸引力。在美国以外，基本上没有对<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>资本配置有意义的候选选择。总的来说，我们没有可能取得惊人的业绩。</p><p>尽管如此，管理<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>大部分时候是有趣的，而且总是引人入胜。从积极的一面来看，经过59年的整合，公司现在拥有的企业——按加权计算——在某种程度上比大多数大型美国公司有更好的前景。通过运气和努力，从大量决策中涌现出了一些巨大的赢家。现在我们有一小批长期的管理者，他们从不考虑去别处，并将65岁仅仅视为另一个生日。</p><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>受益于不同寻常的恒定和清晰的目标。虽然我们强调善待员工、社区和供应商——谁不想这样做呢？——但我们的忠诚将永远献给我们的国家和股东。我们永远不会忘记，虽然你们的资金与我们的混合在一起，但它不属于我们。</p><p>带着这种专注，以及我们目前的业务组合，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>应该比普通美国公司做得稍好一些，更重要的是，也应该以更低的永久性资本损失风险运营。然而，任何超越&quot;略好&quot;的期望都是一厢情愿。当伯蒂全力投入<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>时，这个温和的期望并不存在——但现在它存在了。</p><hr><h2 id="我们的-秘密武器" tabindex="-1">我们的&quot;秘密武器&quot; <a class="header-anchor" href="#我们的-秘密武器" aria-label="Permalink to &quot;我们的&quot;秘密武器&quot;&quot;">​</a></h2><p>偶尔，市场和/或经济会导致一些大型且基本良好的企业的股票和债券被明显错误定价。事实上，市场可能——并且将会——不可预测地冻结甚至消失，就像1914年的四个月和2001年的几天那样。如果你认为美国投资者现在比过去更稳定，回想一下2008年9月。通信速度和技术的奇迹促进了全球瞬时瘫痪，自烟火信号以来我们已经走过了漫长的道路。这种瞬时恐慌不会经常发生——但它们会发生。</p><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>能够立即以巨额资金和确定的表现回应市场冻结，这可能为我们提供偶尔的大规模机会。虽然股票市场比我们早年大了很多，但今天的活跃参与者既不比我在学校时情绪更稳定，也不比那时学得更好。出于某种原因，市场现在表现出比我年轻时更像赌场的行为。赌场现在存在于许多家庭中，每天引诱着居住者。</p><p>一个金融事实永远不应该被遗忘。华尔街——用其比喻意义来说——希望它的客户赚钱，但真正让从业者兴奋的是疯狂的交易活动。在这样的时刻，任何可以被推销的愚蠢都会被大力推销——不是每个人，但总有人会这样做。</p><p>偶尔，场面会变得丑陋。政客们随后变得愤怒；最臭名昭著的作恶者溜走了，富有且未受惩罚；你隔壁的朋友变得困惑、贫穷，有时甚至怀恨在心。他认识到，金钱已经战胜了道德。</p><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>有一条投资规则从未改变，将来也不会改变：永远不要冒永久性资本损失的风险。得益于美国的顺风和复利的力量，如果你一生中做出几个好的决定并避免严重错误，我们所处的领域一直是——并且将继续是——有回报的。</p><p>我相信<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>能够应对任何前所未有的金融灾难。这一能力是我们不会放弃的。当经济动荡发生时，它们会的，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的目标将是为国家服务——就像我们在2008-09年以非常微小的方式所做的那样——帮助扑灭金融大火，而不是成为那些无意或有意点燃熊熊大火的众多公司之一。</p><p>我们的目标是现实的。<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的力量来自于其多元化收益的尼亚加拉大瀑布——在支付利息成本、税款以及大量折旧和摊销之后（EBITDA在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>是禁止使用的指标）。即使国家遇到长时间的全球经济疲软、恐惧和近乎瘫痪，我们也能以最低的现金需求运营。</p><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>目前不支付股息，其股票回购是100%自由裁量的。年度债务到期从不是问题。</p><p>贵公司还持有远超传统智慧认为必要的现金和美国国债头寸。在2008年的恐慌中，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>从运营中产生现金，没有依赖任何形式的商业票据、银行信贷额度或债务市场。我们没有预测经济瘫痪的时间，但我们始终为此做好准备。</p><p>极端的财务保守主义是我们向所有<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>股东做出的企业承诺。在大多数年份——的确在大多数十年里——我们的谨慎可能被证明是不必要的行为——类似于对一座被认为防火的堡垒式建筑投保。然而，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>不想对伯蒂或任何将积蓄托付给我们的人造成永久性财务损害——持续的账面缩水是无法避免的。</p><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>是为持久而建的。</p><hr><h2 id="非控制型企业-让我们安心的持股" tabindex="-1">非控制型企业：让我们安心的持股 <a class="header-anchor" href="#非控制型企业-让我们安心的持股" aria-label="Permalink to &quot;非控制型企业：让我们安心的持股&quot;">​</a></h2><p>去年我提到了<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的两个长期部分持股——<a href="/03_companies/可口可乐.html">可口可乐</a>和<a href="/03_companies/美国运通.html">美国运通</a>。这些不是像我们持有<a href="/03_companies/苹果公司.html">苹果公司</a>那样的大额持仓。每家只占<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>GAAP净资产的4-5%。但它们是有意义的资产，也说明了我们的思维过程。</p><p><a href="/03_companies/美国运通.html">美国运通</a>于1850年开始运营，<a href="/03_companies/可口可乐.html">可口可乐</a>于1886年在亚特兰大一家药店推出。（<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>对新手不太感兴趣。）多年来，两家公司都尝试向不相关领域扩张，但都发现这些尝试收效甚微。在过去——但绝对不是现在——两家公司甚至都被管理不善。</p><p>但每家在其核心业务上都取得了巨大成功，并随着条件的变化不时重塑。至关重要的是，他们的产品&quot;走向世界&quot;。<a href="/03_companies/可口可乐.html">可口可乐</a>和<a href="/03_companies/美国运通.html">美国运通</a>都成为了全球认可的品牌名称，就像他们的核心产品一样，液体消费和无争议的金融信任是我们世界永恒的必需品。</p><p>2023年，我们没有买卖<a href="/03_companies/美国运通.html">美国运通</a>或<a href="/03_companies/可口可乐.html">可口可乐</a>的任何股票——延续了我们自己的&quot;长睡者&quot;——这种沉睡已经持续了二十多年。去年，两家公司都通过增加收益和股息来奖励我们的不作为。事实上，我们2023年获得的<a href="/03_companies/美国运通.html">美国运通</a>收益份额大大超过了我们很久以前购买时花费的13亿美元。</p><p><a href="/03_companies/美国运通.html">美国运通</a>和<a href="/03_companies/可口可乐.html">可口可乐</a>在2024年几乎肯定会增加股息——就<a href="/03_companies/美国运通.html">美国运通</a>而言约为16%——我们肯定会全年保持持股不动。我能创造出比这两家公司更好的全球业务吗？正如伯蒂会告诉你的：&quot;不可能。&quot;</p><p>虽然<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>在2023年没有购买任何一家公司的股票，但由于我们在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>进行的股票回购，你对<a href="/03_companies/可口可乐.html">可口可乐</a>和<a href="/03_companies/美国运通.html">美国运通</a>的间接所有权去年略有增加。这种回购会增加你在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>拥有的每项资产中的参与度。对于这个明显但经常被忽视的事实，我加上我通常的警告：所有股票回购都应该取决于价格。在低于企业价值折价时是明智的，但如果以溢价进行就变成愚蠢了。</p><p><a href="/03_companies/可口可乐.html">可口可乐</a>和<a href="/03_companies/美国运通.html">美国运通</a>的经验教训？当你发现一家真正出色的企业时，坚持持有它。耐心是有回报的，一家有出色的企业可以抵消许多不可避免的平庸决策。</p><hr><p>今年，我想介绍另外两笔我们预计将无限期持有的投资。与<a href="/03_companies/可口可乐.html">可口可乐</a>和<a href="/03_companies/美国运通.html">美国运通</a>一样，这些持仓相对于我们的资源来说并不大。然而，它们是值得的，我们能够在2023年增加两个仓位。</p><p>年底时，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>拥有<a href="/03_companies/西方石油.html">西方石油</a>公司普通股的27.8%，还拥有认股权证，在五年多以后给我们以固定价格大幅增加持股的选择权。虽然我们非常喜欢我们的持股和选择权，但<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>对购买或管理<a href="/03_companies/西方石油.html">西方石油</a>没有兴趣。我们特别欣赏其在美国的大量油气资产，以及在碳捕集方面的领先地位，尽管该技术的经济可行性尚未得到证实。这两项活动都非常符合我们国家的利益。</p><p>不久之前，美国严重依赖外国石油，碳捕集没有有意义的支持者。事实上，1975年，美国产量为每天800万桶油当量（&quot;BOEPD&quot;），远低于国家需求。从有利于二战期间美国动员的能源地位，国家已经退化为严重依赖外国——潜在不稳定的——供应国。石油产量下降和未来需求增加都被预测到了。</p><p>长期以来，悲观情绪似乎是正确的，产量到2007年下降到每天500万桶。与此同时，美国政府在1975年创建了战略石油储备（&quot;SPR&quot;）来缓解——尽管远不能消除——美国自给自足的侵蚀。</p><p>然后——哈利路亚！——2011年，页岩经济变得可行，我们的能源依赖结束了。现在，美国产量超过每天1300万桶，欧佩克不再占据上风。<a href="/03_companies/西方石油.html">西方石油</a>公司本身的美国石油产量每年都接近整个战略石油储备的库存。如果国内产量保持在每天500万桶，而美国发现自己严重依赖非美国来源，我们国家今天会非常——非常——紧张。在那个水平上，如果外国石油变得不可用，战略石油储备将在几个月内耗尽。</p><p>在瓦基·霍洛布的领导下，<a href="/03_companies/西方石油.html">西方石油</a>正在为其国家和所有者做正确的事情。没有人知道油价在下个月、一年或十年内会怎样。但薇姬知道如何从岩石中分离石油，这是罕见的天赋，对她的股东和国家都有价值。</p><hr><p>此外，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>继续持有五家非常大的日本公司的被动长期权益，每家公司都以类似于<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>自身运营的高度多元化方式运营。在格雷格·阿贝尔和我去年访问东京与管理层交谈之后，我们在所有五家公司都增加了持股。</p><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>现在拥有每家公司的约9%。（一个小点：日本公司计算流通股的方式与美国惯例不同。）<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>还向每家公司承诺，不会购买会使我们的持股超过9.9%的股票。</p><p>我们为五家公司的总成本为1.6万亿日元，年底市值为2.9万亿日元。然而，日元近年来走弱，我们以美元计算的年底未实现收益为61%或80亿美元。</p><p>格雷格和我都不相信我们能够预测主要货币的市场价格。我们也不相信我们能雇用具有这种能力的人。因此，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>用1.3万亿日元的债券收益为大部分日本仓位融资。这笔债务在日本非常受欢迎，我相信<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>比任何其他美国公司都拥有更多的日元计价债务。走弱的日元为<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>产生了19亿美元的年底收益，根据GAAP规则，这笔收益在2020-23年期间已定期确认为收入。</p><p>在某些重要方面，所有五家公司——伊藤忠、丸红、三菱、三井和住友——都遵循比美国通常实践更为股东友好的政策。自从我们开始购买日本股票以来，五家公司都以有吸引力的价格减少了流通股数量。</p><p>同时，所有五家公司管理层的自身薪酬激励远不如美国典型那样激进。还要注意，五家公司都只将约三分之一的收益用于股息。这五家公司保留的大量资金用于建设其众多业务，较少用于回购股票。与<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>一样，这五家公司不愿发行股票。</p><p>对<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的另一个好处是，我们的投资可能会带来机会，让我们与五家大型、管理良好且受人尊敬的公司在全球范围内建立合作伙伴关系。他们的利益比我们广泛得多。另一方面，日本CEO们可以放心，知道<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>始终拥有巨大的流动资源，可以立即用于此类合作，无论其规模如何。</p><p>我们的日本购买始于2019年7月4日。考虑到<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>目前的规模，通过公开市场购买建立仓位需要很大的耐心和一段&quot;友好&quot;价格的时期。这个过程就像转动一艘战列舰。这是我们<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>早期没有面临的一个重要劣势。</p><hr><h2 id="_2023年的成绩单" tabindex="-1">2023年的成绩单 <a class="header-anchor" href="#_2023年的成绩单" aria-label="Permalink to &quot;2023年的成绩单&quot;">​</a></h2><p>每个季度我们都会发布新闻稿，报告我们汇总的经营收益（或亏损），类似于下面显示的方式。以下是全年的汇总：</p><table tabindex="0"><thead><tr><th>（单位：百万美元）</th><th style="text-align:right;">2023</th><th style="text-align:right;">2022</th></tr></thead><tbody><tr><td>保险承保</td><td style="text-align:right;">$5,428</td><td style="text-align:right;">$(30)</td></tr><tr><td>保险投资收益</td><td style="text-align:right;">$9,567</td><td style="text-align:right;">$6,484</td></tr><tr><td>铁路</td><td style="text-align:right;">$5,087</td><td style="text-align:right;">$5,946</td></tr><tr><td>公用事业和能源</td><td style="text-align:right;">$2,331</td><td style="text-align:right;">$3,904</td></tr><tr><td>其他业务及杂项</td><td style="text-align:right;">$14,937</td><td style="text-align:right;">$14,549</td></tr><tr><td><strong>经营收益</strong></td><td style="text-align:right;"><strong>$37,350</strong></td><td style="text-align:right;"><strong>$30,853</strong></td></tr></tbody></table><p>在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>2023年5月6日的年度股东大会上，我展示了当天早上早些时候发布的第一季度业绩。然后我对全年前景做了简短总结：(1) 我们大部分非保险业务在2023年面临收益下降；(2) 这一下降将被我们两个最大的非保险业务——<a href="/03_companies/BNSF铁路.html">BNSF铁路</a>和<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>·<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>能源（&quot;BHE&quot;）——的良好业绩所缓冲，这两家公司2022年合计占经营收益的30%以上；(3) 我们的投资收益肯定会大幅增长，因为<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>持有的巨额美国国债终于开始给我们支付远高于我们之前收到的微薄收益；(4) 保险可能表现良好，既因为其承保收益与经济中其他地方的收益不相关，而且财产意外险的价格已经走强。</p><p>保险业务如预期般表现出色。然而，我对我们两个最大业务<a href="/03_companies/BNSF铁路.html">BNSF铁路</a>和BHE的预期是错误的。让我们看看每一个。</p><hr><p>铁路对美国的经济未来至关重要。从成本、燃料使用和碳强度来看，它显然是将重型货物运往远方最有效的方式。卡车在短途运输中胜出，但美国人需要的许多货物必须运往数百甚至数千英里外的客户。没有铁路，这个国家无法运转，而且该行业的资本需求始终巨大。与大多数美国企业相比，铁路是资本密集型的。</p><p><a href="/03_companies/BNSF铁路.html">BNSF铁路</a>是覆盖北美的六大铁路系统中最大的一个。我们的铁路在其资产负债表上以700亿美元记录了23,759英里的主线、99条隧道、13,495座桥梁、7,521台机车和各种其他固定资产。但我的猜测是，复制这些资产至少需要5000亿美元，而且需要数十年才能完成。</p><p><a href="/03_companies/BNSF铁路.html">BNSF铁路</a>每年必须花费超过其折旧费用，以维持其目前的业务水平。这一现实对所有者不利，无论他们投资于哪个行业，但在资本密集型行业中尤其不利</p>',102)])])}const f=t(o,[["render",m]]);export{c as __pageData,f as default};
